import { useState } from "react";

const answers = [
  "Yes!",
  "No.",
  "Maybe...",
  "Definitely!",
  "Ask again later.",
  "Absolutely not.",
  "Without a doubt.",
  "Very unlikely.",
  "It is certain.",
  "The future is unclear."
];

export default function CrystalBall() {
  const [answer, setAnswer] = useState("Ask me anything!");

  function shakeBall() {
    const randomIndex = Math.floor(Math.random() * answers.length);
    setAnswer(answers[randomIndex]);
  }

  return (
    <div style={{ textAlign: "center" }}>
      <div
        style={{
          width: 250,
          height: 250,
          borderRadius: "50%",
          background: "#222",
          color: "white",
          display: "grid",
          placeItems: "center",
          margin: "20px auto",
          padding: "20px",
          fontSize: "1.3rem",
          fontWeight: "bold",
        }}
      >
        {answer}
      </div>

      <button onClick={shakeBall}>
        🔮 Shake the Crystal Ball
      </button>
    </div>
  );
}
